### Problem Description

When utilizing a `must_not` knn pre-filter, it is possible that nested kNN vector search fails. It will fail with an error similar to: "Parent query must not match any docs besides parent filter"

### Steps to Reproduce

```
PUT nested_text
{
  "mappings": {
    "properties": {
      "range": {
        "type": "long"
      },
      "i_am_parent": {
        "type": "constant_keyword"
      },
      "paragraphs": {
        "type": "nested",
        "properties": {
          "vector": {
            "type": "dense_vector",
            "dims": 2,
            "index": "true",
            "similarity": "cosine"
          }
        }
      }
    }
  }
}

POST _bulk
{ "index" : { "_index" : "nested_text", "_id" : "1" } }
{ "publish_date" : "1", "i_am_parent": "yes", "paragraphs": [ {"vector": [ 1, 1 ], "text": "some text" }, {"vector": [1, 2], "text": "some text"} ] }
{ "index" : { "_index" : "nested_text", "_id" : "2" } }
{ "i_am_parent": "yes", "paragraphs": [ {"vector": [ 2, 1 ], "text": "some text" }, {"vector": [2, 2], "text": "some text"} ] }
{ "index" : { "_index" : "nested_text", "_id" : "3" } }
{ "publish_date" : "2", "i_am_parent": "yes", "paragraphs": [ {"vector": [ 3, 1 ], "text": "some text" }, {"vector": [3, 2], "text": "some text"} ] }
{ "index" : { "_index" : "nested_text", "_id" : "4" } }
{ "i_am_parent": "yes", "paragraphs": [ {"vector": [ 4, 1 ], "text": "some text" }, {"vector": [4, 2], "text": "some text"} ] }
{ "index" : { "_index" : "nested_text", "_id" : "5" } }
{ "publish_date" : "7", "i_am_parent": "yes", "paragraphs": [ {"vector": [ 5, 1 ], "text": "some text" }, {"vector": [5, 2], "text": "some text"} ] }


POST nested_text/_search
{
  "query": {
    "nested": {
      "path": "paragraphs",
      "query": {
        "knn": {
          "query_vector": [1, 2],
          "field": "paragraphs.vector",
          "num_candidates": 10,
          "filter": [
            {
              "bool": {
                "must_not": {
                  "exists": {
                    "field": "publish_date"
                  }
                }
              }
            }
          ]
        }
      }
    }
  }
}
```

